module adder_pipe_64bit
(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output [64:0] result,
    output o_en
);
reg i_en_reg1, i_en_reg2, i_en_reg3;
reg [63:0] adda_reg1, adda_reg2, adda_reg3;
reg [63:0] addb_reg1, addb_reg2, addb_reg3;
reg [64:0] result_reg1, result_reg2, result_reg3;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        i_en_reg1 <= 1'b0;
        i_en_reg2 <= 1'b0;
        i_en_reg3 <= 1'b0;
        adda_reg1 <= 64'b0;
        adda_reg2 <= 64'b0;
        adda_reg3 <= 64'b0;
        addb_reg1 <= 64'b0;
        addb_reg2 <= 64'b0;
        addb_reg3 <= 64'b0;
        result_reg1 <= 65'b0;
        result_reg2 <= 65'b0;
        result_reg3 <= 65'b0;
    end
    else begin
        i_en_reg1 <= i_en;
        i_en_reg2 <= i_en_reg1;
        i_en_reg3 <= i_en_reg2;
        adda_reg1 <= adda;
        adda_reg2 <= adda_reg1;
        adda_reg3 <= adda_reg2;
        addb_reg1 <= addb;
        addb_reg2 <= addb_reg1;
        addb_reg3 <= addb_reg2;
        result_reg1 <= adda_reg1 + addb_reg1;
        result_reg2 <= result_reg1;
        result_reg3 <= result_reg2;
    end
end
assign result = result_reg3;
assign o_en = i_en_reg3 & i_en_reg2 & i_en_reg1;
endmodule
